// Evaluate Runs (aggregate across ALL incoming items)
const items = $input.all().map(i => i.json);

// Flatten possible shapes into runs[]
// Supports:
// 1) Each item is a run object (your current case)
// 2) One item is an array of runs
// 3) One item has { data: [...] } or { runs: [...] }
let runs = [];
for (const x of items) {
  if (Array.isArray(x)) {
    runs.push(...x);
  } else if (Array.isArray(x?.data)) {
    runs.push(...x.data);
  } else if (Array.isArray(x?.runs)) {
    runs.push(...x.runs);
  } else if (x && (x.run_id || x.status)) {
    runs.push(x);
  }
}

// De-dupe by run_id (helps if polling returns duplicates)
const seen = new Set();
runs = runs.filter(r => {
  const id = r?.run_id ?? r?.runId ?? JSON.stringify(r);
  if (seen.has(id)) return false;
  seen.add(id);
  return true;
});

const terminal = new Set(["COMPLETED","FAILED","CANCELLED"]);
const allDone =
  runs.length > 0 &&
  runs.every(r => terminal.has(String(r.status || "").toUpperCase()));

// Preserve full raw input (all items) so nothing is lost
return [{
  json: {
    raw: items,   // full original input across all items
    runs,         // normalized array of runs
    allDone
  }
}];

// Rehydrate per-run items from aggregated Check-If-Complete payload
// Input is usually ONE item with shape: { runs: [...], raw: [...], allDone: bool }

const inItem = $input.first().json;

// Prefer runs, fall back to raw, then empty
const arr = Array.isArray(inItem.runs)
  ? inItem.runs
  : (Array.isArray(inItem.raw) ? inItem.raw : []);

// Extract run IDs
const runIds = arr
  .map(r => r?.run_id || r?.runId)
  .filter(Boolean);

// Optionally preserve aggregated context for later nodes
// (useful if you want to carry question/competitors forward)
const ctx = {
  // keep these if they exist upstream
  question: inItem.question,
  competitors: inItem.competitors,
  byName: inItem.byName,
};

return runIds.map(runId => ({
  json: {
    ...ctx,
    runId,
    run_id: runId
  }
}));

// Parse competitors from form input
const formData = $input.first().json;
const competitorsText = (formData.competitors || '').trim();
const question = (formData.question || '').trim();

function normalizeUrl(raw) {
  if (!raw) return '';
  let u = raw.trim();

  // Remove trailing punctuation that often gets pasted
  u = u.replace(/[),.;]+$/, '');

  // If user pasted just domain or www., add scheme
  if (!/^https?:\/\//i.test(u)) {
    u = 'https://' + u;
  }

  // Basic sanity: if it's still not a domain-like string, return empty
  // (optional, but helps avoid garbage)
  const hostish = u.replace(/^https?:\/\//i, '');
  if (!hostish.includes('.')) return '';

  return u;
}

function splitNameAndUrl(line) {
  // Remove bullets like "- " "* " "• "
  const clean = line.replace(/^\s*[-*•]\s*/, '').trim();

  // Prefer em dash delimiter
  if (clean.includes('—')) {
    const [name, ...rest] = clean.split('—');
    return { name: name.trim(), url: rest.join('—').trim() };
  }

  // Fallback: hyphen delimiter (only split on " - " to avoid breaking names like "Foo-Bar")
  if (clean.includes(' - ')) {
    const [name, ...rest] = clean.split(' - ');
    return { name: name.trim(), url: rest.join(' - ').trim() };
  }

  // Fallback: try to find a domain-like token anywhere in the line
  const m = clean.match(/\b((?:https?:\/\/)?(?:www\.)?[a-z0-9.-]+\.[a-z]{2,}(?:\/\S*)?)\b/i);
  if (m) {
    const rawUrl = m[1];
    const name = clean.replace(rawUrl, '').replace(/[-—\s]+$/, '').trim();
    return { name: name.trim(), url: rawUrl.trim() };
  }

  // If no URL found, treat whole line as name
  return { name: clean, url: '' };
}

const competitorLines = competitorsText
  .split(/\r?\n/)
  .map(s => s.trim())
  .filter(Boolean);

const competitors = competitorLines.map((line, index) => {
  const { name, url } = splitNameAndUrl(line);
  return {
    id: `competitor-${index + 1}`,
    name,
    url: normalizeUrl(url),
    question
  };
});

return competitors.map(c => ({ json: c }));

// Build a numbered competitor list from all items
const items = $input.all();

let competitorList = '';
let question = '';

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  if (i === 0 && item.question) question = item.question;

  if (item.name && item.url) {
    competitorList += `${i + 1}. ${item.name} (${item.url})`;
    if (i < items.length - 1) competitorList += '\n';
  }
}

return {
  json: {
    competitorList,
    question
  }
};

// Parse the OpenAI JSON response and extract goals (matches your OpenAI node schema)
const j = $input.first().json;

// The JSON string is here:
// j.output[0].content[0].text
const text =
  j?.output?.[0]?.content?.find(c => c?.type === 'output_text')?.text
  ?? j?.output?.[0]?.content?.[0]?.text
  ?? null;

if (!text || typeof text !== 'string') {
  return [{
    json: {
      error: 'No output_text.text found in OpenAI response',
      availableKeys: Object.keys(j || {}),
      sample: j
    }
  }];
}

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  // In case the model wrapped JSON in ```json fences (just in case)
  const stripped = text.replace(/```json\s*|```/g, '').trim();
  parsed = JSON.parse(stripped);
}

const goals = Array.isArray(parsed?.goals) ? parsed.goals : [];

return goals.map(g => ({
  json: {
    competitor_name: g.competitor_name || '',
    competitor_url: g.competitor_url || '',
    goal: g.goal || ''
  }
}));

// Prepare Tinyfish run parameters from matched competitor and goal data
const item = $input.item.json;

let runUrl = item.competitor_url || item.url || '';
if (runUrl && !runUrl.startsWith('http://') && !runUrl.startsWith('https://')) {
  runUrl = 'https://' + runUrl;
}

let runGoal = '';
if (item.goal) {
  runGoal = item.goal;
} else {
  const question = item.question || 'research this competitor';
  const name = item.name || item.competitor_name || 'this competitor';
  runGoal = `Find information relevant to: ${question} on ${name}'s website.`;
}

runGoal += '\n\nWhen you find evidence, list the exact source URLs (including child pages you visited) in a "sources" list.';

return {
  json: {
    id: item.id,
    name: item.name || item.competitor_name,
    url: item.url,
    runUrl,
    runGoal,
    question: item.question
  }
};

