// Aggregate competitor context from "Match Competitors with Goals"
// and Tinyfish run results from the current input (Check If Complete output).

// 1) Pull ALL competitor+goal items (not just one)
const compItems = $("Match Competitors with Goals1")?.all?.() ?? [];
const competitors = compItems.map((it) => {
  const j = it.json ?? {};
  return {
    id: j.id ?? null,
    name: j.name ?? j.competitor_name ?? "",
    url: j.url ?? "",
    runUrl: j.runUrl ?? j.competitor_url ?? j.url ?? "",
    runGoal: j.runGoal ?? j.goal ?? "",
    question: j.question ?? "",
  };
}).filter(c => c.name);

// 2) Derive question (prefer the first non-empty)
const question =
  competitors.find(c => c.question)?.question ??
  "";

// 3) Get ALL runs from current node input
// Your Check If Complete input appears to be an array of run objects.
// In n8n Code node, $input.all() returns items; each item has .json.
// If your IF node passes the whole array as one item, it'll be in item.json.
// Handle both shapes: [run, run] OR { data: [run, run] } OR single run.
const inItems = $input.all().map(i => i.json);

// Flatten possible shapes into `runsRaw`
let runsRaw = [];
for (const x of inItems) {
  if (Array.isArray(x)) {
    runsRaw.push(...x);
  } else if (Array.isArray(x?.data)) {
    runsRaw.push(...x.data);
  } else if (Array.isArray(x?.runs)) {
    runsRaw.push(...x.runs);
  } else if (x?.run_id || x?.status) {
    runsRaw.push(x);
  }
}

// 4) Normalize runs and extract useful fields
const runs = runsRaw.map((run) => {
  const status = String(run.status ?? "").toUpperCase();
  const resultObj = run.result ?? null;

  const sources =
    Array.isArray(resultObj?.sources) ? resultObj.sources :
    Array.isArray(run.sources) ? run.sources :
    null;

  return {
    run_id: run.run_id ?? null,
    status,
    goal: run.goal ?? "",
    created_at: run.created_at ?? null,
    started_at: run.started_at ?? null,
    finished_at: run.finished_at ?? null,
    error: run.error ?? null,
    sources,
    result: resultObj,
    rawResultText: resultObj ? JSON.stringify(resultObj, null, 2) : "",
  };
});

// 5) Optional: map results by competitor name if it exists in goal text
// (best-effort only; you said matching is not required)
const byName = {};
for (const c of competitors) {
  byName[c.name] = {
    competitor: c,
    runs: runs.filter(r => (r.goal || "").toLowerCase().includes(c.name.toLowerCase())),
  };
}

// 6) Return ONE aggregated item for downstream OpenAI
return [{
  json: {
    question,
    competitors,
    runs,
    byName,
    allDone: runs.length > 0 && runs.every(r => ["COMPLETED", "FAILED", "CANCELLED"].includes(r.status)),
  }
}];

// Build Research Payload Text
const root = $input.first().json;

// Always take arrays directly (no matching, no filtering)
const competitors = Array.isArray(root.competitors) ? root.competitors : [];
const runs = Array.isArray(root.runs) ? root.runs : [];

// Build a "no-loss" payload for the LLM
const payload = {
  question: root.question ?? competitors?.[0]?.question ?? "",
  allDone: root.allDone ?? null,
  competitorCount: competitors.length,
  runCount: runs.length,
  competitors,  // FULL objects
  runs,         // FULL objects
  byName: root.byName ?? null, // optional, keep if present
};

return [{
  json: {
    question: payload.question,
    competitors,
    runs,
    allDone: payload.allDone,
    competitorCount: payload.competitorCount,
    runCount: payload.runCount,
    researchPayloadText: JSON.stringify(payload, null, 2),
  }
}];

const root = $input.first().json;

// The OpenAI node output you showed looks like:
// [ { output: [ { content: [ { text: "..." } ] } ] } ]
// But in n8n, we typically receive ONE item whose json has fields like `output`.

const output = root.output ?? root.data?.output ?? null;

let textParts = [];

if (Array.isArray(output)) {
  for (const msg of output) {
    const content = msg?.content;
    if (Array.isArray(content)) {
      for (const c of content) {
        if (typeof c?.text === 'string' && c.text.trim()) textParts.push(c.text);
      }
    }
  }
}

// Fallbacks (some n8n OpenAI nodes return message/content directly)
if (textParts.length === 0) {
  const fallback = root.message?.content ?? root.message ?? root.text ?? root.output_text ?? '';
  if (typeof fallback === 'string' && fallback.trim()) textParts = [fallback];
}

const report = textParts.join('\n\n').trim();

return [{
  json: {
    ...root,
    report,
    report_format: 'markdown'
  }
}];

const items = $input.all().map(i => i.json);

// Heuristic: pick the item that has "runs" as research payload
const research = items.find(x => Array.isArray(x.runs) || Array.isArray(x.competitors)) || {};
// pick the item that has reportMarkdown
const reportP = items.find(x => typeof x.report === "string") || {};

return [{
  json: {
    ...research,
    report: reportP.report || "",
    generatedAt: new Date().toISOString(),
  }
}];

const j = $json;

const question = j.question || '';
const competitors = j.competitor_names
  || (Array.isArray(j.competitors) ? j.competitors.map(c => c.name).join(', ') : '')
  || '';

const report = j.report_md || j.reportMarkdown || '';

const createdAt = j.created_at || j.createdAt || new Date().toISOString();
const safe = (question || 'report')
  .replace(/[^a-z0-9-_ ]/gi, '')
  .slice(0, 60)
  .trim()
  .replace(/\s+/g, '-');

const mdFilename = `competitive-research-${safe || 'report'}-${Date.now()}.md`;

const mdContent =
`# Competitive Research

**Question:** ${question}
**Competitors:** ${competitors}
**Created:** ${createdAt}

---

${report}
`;

return [{
  json: {
    mdFilename,
    mdContent
  }
}];

const baseName = ($json.mdFilename || `competitive-research-${Date.now()}`).trim();

// Force .md extension
const filename = baseName.toLowerCase().endsWith('.md') ? baseName : `${baseName}.md`;

const md = $json.mdContent || '';

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(md, 'utf8'),
  filename,
  'text/markdown'
);

return [{
  json: { mdFilename: filename }, // optional, safe to keep
  binary: { data: binaryData }
}];

const data = $json;
const content = JSON.stringify(data, null, 2);
const filename = `scout-results-${Date.now()}.json`;

return [{
  json: data,
  binary: {
    data: await this.helpers.prepareBinaryData(
      Buffer.from(content, "utf8"),
      filename,
      "application/json"
    )
  }
}];
